fn length(s: &String) -> usize {
    s.len()
}

fn main() {
    let s = String::from("hello");
    let len = length(&s);
    println!("{} has {} bytes", s, len);
}

fn main() {
    let s = String::from("hello");
    let r1 = &s;
    let r2 = &s;
    let r3 = &s;
    println!("{} {} {}", r1, r2, r3);
}

fn append_world(s: &mut String) {
    s.push_str(" world");
}

fn main() {
    let mut s = String::from("hello");
    append_world(&mut s);
    println!("{}", s);
}

fn main() {
    let mut s = String::from("hello");
    let r1 = &mut s;
    let r2 = &mut s; // error!
    println!("{} {}", r1, r2);
}

fn main() {
    let mut s = String::from("hello");
    let r1 = &s;
    let r2 = &mut s; // error while r1 is active!
    println!("{} {}", r1, r2);
}

fn main() {
    let mut s = String::from("hello");
    let r1 = &s;
    println!("{}", r1); // r1 last used here, borrow ends
    let r2 = &mut s;    // now safe to mutate
    r2.push_str(" world");
    println!("{}", r2);
}

fn dangle() -> String {
    let s = String::from("hello");
    s // Return the String itself, not a reference
}

fn main() {
    let s = dangle();
    println!("{}", s);
}

fn summarise(text: &str) -> usize {
    text.split_whitespace().count()
}

fn main() {
    let speech = String::from("to be or not to be");
    let words = summarise(&speech);
    println!("{} words: '{}'", words, speech);
}
